// Get EPR data and outreach log from merged inputs
const allInputs = $input.all();
const eprData = [];
const outreachLog = [];

// Separate the merged data
for (const item of allInputs) {
  if (item.json['MEMBER NAME'] !== undefined) {
    eprData.push(item.json);
  } else if (item.json['station_code'] !== undefined || item.json['member_name'] !== undefined) {
    outreachLog.push(item.json);
  }
}

const THRESHOLD = 90;
const COOLDOWN_DAYS = 30;
const MAX_PER_RUN = 30; // Max to process - 30 allows up to 10 per rep (3 reps)

// Build set of recently contacted station codes
const now = new Date();
const recentlyContacted = new Set();

for (const log of outreachLog) {
  const sentAt = log.sent_at || log.processed_at || log.failed_at;
  if (sentAt && log.station_code) {
    const logDate = new Date(sentAt);
    const daysSince = (now - logDate) / (1000 * 60 * 60 * 24);
    if (daysSince <= COOLDOWN_DAYS) {
      recentlyContacted.add(log.station_code);
    }
  }
}

// Filter EPR data
const candidates = [];

for (const row of eprData) {
  const memberName = row['MEMBER NAME'] || '';
  const stationCode = row['STATION CODE'] || '';
  const ticketsReceived = parseInt(String(row['TICKETS RECEIVED'] || '0').replace(/,/g, ''), 10) || 0;
  const responsesNeeded = parseInt(String(row['RESPONSES NEEDED'] || '0').replace(/,/g, ''), 10) || 0;
  const totalResponsesSent = parseInt(String(row['TOTAL RESPS SENT'] || '0').replace(/,/g, ''), 10) || 0;

  let responseRate;
  const rateRaw = row['% RESPONDED'];
  if (rateRaw !== undefined && rateRaw !== null && rateRaw !== '') {
    responseRate = parseFloat(String(rateRaw).replace('%', ''));
  } else if (responsesNeeded > 0) {
    responseRate = Math.round((totalResponsesSent / responsesNeeded) * 100);
  } else {
    responseRate = 100;
  }

  // Skip if no station code or member name
  if (!stationCode || !memberName) continue;

  // Skip if compliant
  if (responseRate >= THRESHOLD) continue;

  // Skip if no responses needed
  if (responsesNeeded === 0) continue;

  // Skip if recently contacted
  if (recentlyContacted.has(stationCode)) continue;

  candidates.push({
    json: {
      member_name: memberName,
      station_code: stationCode,
      tickets_received: ticketsReceived,
      responses_needed: responsesNeeded,
      responses_sent: totalResponsesSent,
      response_rate: responseRate,
      threshold: THRESHOLD,
      below_threshold_by: THRESHOLD - responseRate
    }
  });
}

// Limit to avoid API overload
if (candidates.length === 0) {
  return [{ json: { no_results: true, message: 'No members need outreach (all compliant or recently contacted)' } }];
}

// Return limited set for processing
return candidates.slice(0, MAX_PER_RUN);

// Process ALL items, not just first
const allInputs = $input.all();
const allEprData = $('Filter Candidates').all();
const results = [];

for (let i = 0; i < allInputs.length; i++) {
  const input = allInputs[i].json;
  const eprData = allEprData[i]?.json || {};

  if (!input.results || input.results.length === 0) {
    results.push({
      json: {
        ...eprData,
        hubspot_found: false,
        skip_reason: 'Station code not found in HubSpot'
      }
    });
  } else {
    results.push({
      json: {
        ...eprData,
        hubspot_found: true,
        hubspot_station_id: input.results[0].id
      }
    });
  }
}

return results;

// Process ALL items
const allInputs = $input.all();
const allProcessSearch = $('Process Search').all();
const results = [];

for (let i = 0; i < allInputs.length; i++) {
  const assoc = allInputs[i].json;
  const eprData = allProcessSearch[i]?.json || {};
  const companyId = assoc.results?.[0]?.toObjectId;

  results.push({
    json: {
      ...eprData,
      company_id: companyId || null
    }
  });
}

return results;

// Process ALL items
const allInputs = $input.all();
const allCompany = $('Get Company').all();
const allExtract = $('Extract Company ID').all();
const results = [];

for (let i = 0; i < allInputs.length; i++) {
  const owner = allInputs[i].json;
  const company = allCompany[i]?.json || {};
  const eprData = allExtract[i]?.json || {};

  const ownerEmail = (owner.email || '').toLowerCase();

  if (ownerEmail === 'nick.white@usan.org') {
    results.push({
      json: {
        ...eprData,
        skip: true,
        skip_reason: 'Nick company - excluded from automation',
        owner_email: ownerEmail,
        company_name: company.properties?.name || ''
      }
    });
  } else {
    results.push({
      json: {
        ...eprData,
        skip: false,
        owner_email: ownerEmail,
        company_name: company.properties?.name || '',
        owner_id: company.properties?.hubspot_owner_id
      }
    });
  }
}

return results;

// Process ALL items
const allInputs = $input.all();
const allCheckOwner = $('Check Owner').all();
const results = [];

for (let i = 0; i < allInputs.length; i++) {
  const assoc = allInputs[i].json;
  const eprData = allCheckOwner[i]?.json || {};

  const memberRep = assoc.results?.find(a => 
    a.associationTypes?.some(t => t.typeId === 36 || t.label === 'Member Representative')
  );

  const contactId = memberRep?.toObjectId || assoc.results?.[0]?.toObjectId;

  if (!contactId) {
    results.push({
      json: {
        ...eprData,
        contact_found: false,
        skip_reason: 'No contact found'
      }
    });
  } else {
    results.push({
      json: {
        ...eprData,
        contact_found: true,
        contact_id: contactId
      }
    });
  }
}

return results;

// Process ALL items
const allInputs = $input.all();
const allFindContact = $('Find Contact').all();
const results = [];

for (let i = 0; i < allInputs.length; i++) {
  const contact = allInputs[i].json;
  const eprData = allFindContact[i]?.json || {};

  const firstName = contact.properties?.firstname || (eprData.member_name || '').split(' ')[0];
  const email = contact.properties?.email;

  if (!email) {
    results.push({
      json: {
        ...eprData,
        skip: true,
        skip_reason: 'Contact has no email'
      }
    });
  } else {
    results.push({
      json: {
        ...eprData,
        first_name: firstName,
        last_name: contact.properties?.lastname || '',
        email: email,
        contact_name: `${firstName} ${contact.properties?.lastname || ''}`.trim()
      }
    });
  }
}

return results;

