const allInputs = $input.all();
const results = [];

// ============ TEST MODE CONFIG ============
const TEST_MODE = true;
const TEST_EMAIL = 'christian.olesen@usan.org';
// ==========================================

const REP_DETAILS = {
  'christian.olesen@usan.org': { name: 'Christian Olesen', title: 'Member Services Specialist', phone: 'REDACTED_PHONE', calendly: 'https://calendly.com/christian-olesen-usan/30min', calendlyText: "Christian's Availability" },
  'germain.suess@usan.org': { name: 'Germain Suess', title: 'Member Services Specialist', phone: 'REDACTED_PHONE', calendly: 'https://calendly.com/germain-usan/yearly-membership-review', calendlyText: "Germain's Availability" },
  'trevor.harris@usan.org': { name: 'Trevor Harris', title: 'Member Services Lead', phone: 'REDACTED_PHONE', calendly: 'https://calendly.com/trevor-harris-kr8/yearly-membership-review', calendlyText: "Trevor's Availability" }
};

const LOGO_URL = 'https://i.imgur.com/v6diEdK.jpg';
const BANNER_URL = 'https://i.imgur.com/HfkbUwp.png';

const staticData = $getWorkflowStaticData('global');
if (!staticData.repCounts) staticData.repCounts = {};

for (const item of allInputs) {
  const data = item.json;

  if (!data.email || data.skip) {
    results.push({ json: { ...data, skip: true } });
    continue;
  }

  const ownerEmail = (data.owner_email || '').toLowerCase();
  const rep = REP_DETAILS[ownerEmail] || REP_DETAILS['christian.olesen@usan.org'];
  const repKey = ownerEmail || 'christian.olesen@usan.org';
  staticData.repCounts[repKey] = (staticData.repCounts[repKey] || 0) + 1;

  if (staticData.repCounts[repKey] > 10) {
    results.push({ json: { ...data, skip: true, skip_reason: `Rep ${rep.name} has reached 10 emails this run`, rep_name: rep.name } });
    continue;
  }

  const SIGNATURE_HTML = `<p style="font-family: Aptos, sans-serif; font-size: 12pt;">Thank you,</p><br><table cellspacing="0" cellpadding="0" style="border-collapse: collapse;"><tr><td style="padding-right: 15px; vertical-align: top; border-right: 1.5pt solid #000;"><img src="${LOGO_URL}" alt="USAN 811" width="175" style="max-width: 175px;"></td><td style="padding-left: 15px; vertical-align: top;"><p style="margin: 0; font-family: 'Aptos Display', Aptos, sans-serif; font-size: 12pt;"><b>${rep.name}</b></p><p style="margin: 0; font-family: 'Aptos Display', Aptos, sans-serif; font-size: 12pt;">${rep.title}</p><p style="margin: 0; font-family: 'Aptos Display', Aptos, sans-serif; font-size: 12pt;">${rep.phone}</p><p style="margin: 0; font-family: 'Aptos Display', Aptos, sans-serif; font-size: 12pt;"><a href="http://www.undergroundservicealert.org/" style="color: #0563c1;">undergroundservicealert.org</a></p><p style="margin: 0; font-family: 'Aptos Display', Aptos, sans-serif; font-size: 12pt;">4005 Port Chicago Hwy #100 Concord, CA 94520</p><p style="margin: 0; font-family: 'Aptos Display', Aptos, sans-serif; font-size: 12pt;"><a href="${rep.calendly}" style="color: #4c94d8;"><b>${rep.calendlyText}</b></a></p></td></tr></table><br><a href="https://www.undergroundservicealert.org/damage-prevention-portal/"><img src="${BANNER_URL}" alt="NEW Damage Prevention Portal" width="450" style="max-width: 450px;"></a><br><br><p style="font-size: 9pt; color: #666; font-family: Aptos, sans-serif;">This message contains confidential information and is intended only for the intended recipients. If you are not an intended recipient you should not disseminate, distribute or copy this e-mail. Please notify us immediately by e-mail if you have received this e-mail by mistake and delete this e-mail from your system.</p>`;

  const emailBody = `<!DOCTYPE html><html><head><meta charset="utf-8"></head><body style="font-family: 'Times New Roman', Times, serif; font-size: 11pt;"><p style="font-family: 'Times New Roman', Times, serif; font-size: 11pt;"><strong>${data.first_name}</strong>,</p><p style="font-family: 'Times New Roman', Times, serif; font-size: 11pt; background-color: #FFFF00; padding: 5px; display: inline-block;"><strong>Your current EPR response rate: ${data.response_rate}%</strong> (${data.responses_sent} of ${data.responses_needed} responses)</p><p style="font-family: 'Times New Roman', Times, serif; font-size: 11pt;">Just reaching out because Electronic Positive Responses are still not being posted on the tickets that <strong>${data.member_name}</strong> is receiving.</p><p style="font-family: 'Times New Roman', Times, serif; font-size: 11pt; margin: 15px 0; padding: 10px; border-left: 3px solid #ccc; background: #f9f9f9;"><em>4216.3.(c) (1) (A) Every operator shall supply an electronic positive response through the regional notification center before the legal excavation start date and time.</em> — <a href="https://leginfo.legislature.ca.gov/faces/codes_displayText.xhtml?lawCode=GOV&division=5.&title=1.&part=&chapter=3.1.&article=2">California Government Code 4216</a></p><p style="font-family: 'Times New Roman', Times, serif; font-size: 11pt;">To be in compliance you will need to post EPR on all tickets that you have received. By being out of compliance, <strong>mandatory training and/or fines can be imposed by the Underground Safety Board</strong>.</p><p style="font-family: 'Times New Roman', Times, serif; font-size: 11pt;">To post EPR on the tickets that you receive please login to the Damage Prevention Portal and follow the instructions in our video:</p><ul style="font-family: 'Times New Roman', Times, serif; font-size: 11pt;"><li><strong>CA DPP Login:</strong> <a href="https://appsca.undergroundservicealert.org/pcadmin/Account/Login">https://appsca.undergroundservicealert.org/pcadmin/Account/Login</a></li><li><strong>How to use Electronic Positive Response:</strong> <a href="https://www.youtube.com/watch?v=c1b6HlX-fx4">https://www.youtube.com/watch?v=c1b6HlX-fx4</a></li></ul><p style="font-family: 'Times New Roman', Times, serif; font-size: 11pt;">If you would like to schedule a meeting with me, here is my availability: <a href="${rep.calendly}"><strong>Schedule a Meeting</strong></a></p><p style="font-family: 'Times New Roman', Times, serif; font-size: 11pt;">Please let me know if you have any questions.</p>${SIGNATURE_HTML}</body></html>`;

  let subject = `${data.first_name}, EPR Compliance - Action Required (${data.response_rate}%)`;
  let finalEmail = data.email;
  let finalBody = emailBody;

  if (TEST_MODE) {
    finalEmail = TEST_EMAIL;
    subject = `[TEST] ${subject}`;
    const testBanner = `<div style="background-color: #ff6b6b; color: white; padding: 15px; margin-bottom: 20px; border-radius: 5px; font-family: Arial, sans-serif;"><strong>TEST MODE - This email would be sent to:</strong><br><strong>Recipient:</strong> ${data.email}<br><strong>Contact:</strong> ${data.contact_name || data.first_name}<br><strong>Member:</strong> ${data.member_name}<br><strong>Rep:</strong> ${rep.name}</div>`;
